const body = $input.first().json.body;
// name — default to 'Friend' if absent
const name = body.name?.trim() || 'Friend';
// email — trim + lowercase
const email = body.email?.trim().toLowerCase();
// phone — normalize to international format (worldwide)
// Strips formatting chars, preserves '+', handles 00-prefix country codes
const phone = (() => {
  if (!body.phone) return body.phone;
  const raw = body.phone.toString().trim();
  const cleaned = raw.replace(/[^\d+]/g, '');   // strip spaces, dashes, parens
  if (cleaned.startsWith('+')) return cleaned;   // already international ✅
  const digits = cleaned.replace(/^0+/, '');     // strip leading zeros
  if (digits.length >= 11) return '+' + digits;  // 11+ digits = has country code
  return cleaned;                                 // short local number, return as-is
})();
// lead_source — optional, default to 'Unknown'
const lead_source = body.lead_source?.trim() || 'Unknown';
// service_of_interest — optional, default to 'General Inquiry'
const service_of_interest = body.service_of_interest?.trim() || 'General Inquiry';
const firstName = name.split(' ')[0];
// sms_consent — fail-safe default to false; only true if explicitly sent as true
const sms_consent = body.sms_consent === true || body.sms_consent === 'true';
return [
  {
    json: {
      name,
      email,
      phone,
      first_name:           firstName,
      stage:                1,
      next_followup_at:     new Date().toISOString(),
      has_replied:          false,
      lead_source,
      service_of_interest,
      sms_consent
    }
  }
];

// Runs even when GSheets returns 0 items (no match found).
// Re-injects the sanitized payload with an isDuplicate flag.

const lookupRows = $input.all();
const sanitized  = $('Sanitize Data').first().json;

const isDuplicate =
  lookupRows.length > 0 &&
  lookupRows[0].json['Email'] !== undefined &&
  lookupRows[0].json['Email'] !== '';

return [
  {
    json: {
      ...sanitized,
      isDuplicate
    }
  }
];
